-- 20260516000004_gifting_rules.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Gifting Rules (Story 4.1) ───────────────────────────────────────────────
--
-- L3 Admin configures per-occasion gifting policies: budget cap per recipient,
-- auto-approve threshold, scope (company-wide or specific department), and an
-- optional preferred-vendor list (filters gifting shop for the employee).
--
-- Occasions may be fixed-date (Diwali) or dynamic-trigger (employee birthday
-- pulled from HRMS). Fixed-date occasions carry trigger_date; dynamic
-- triggers carry trigger_kind (e.g. 'birthday', 'work_anniversary').

CREATE TABLE IF NOT EXISTS public.gifting_rules (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  corporate_id UUID NOT NULL REFERENCES public.corporate_accounts(id) ON DELETE CASCADE,
  occasion_name TEXT NOT NULL,
  trigger_kind TEXT NOT NULL CHECK (
    trigger_kind IN ('fixed_date', 'birthday', 'work_anniversary', 'manual')
  ),
  trigger_date DATE,
  budget_per_recipient NUMERIC(12, 2) NOT NULL CHECK (budget_per_recipient > 0),
  requires_approval BOOLEAN DEFAULT FALSE,
  scope TEXT NOT NULL DEFAULT 'company' CHECK (scope IN ('company', 'department')),
  scope_value TEXT,
  preferred_vendor_ids UUID[] DEFAULT '{}'::UUID[],
  is_active BOOLEAN DEFAULT TRUE,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_gifting_rules_corp_active ON public.gifting_rules (corporate_id, is_active);
CREATE INDEX IF NOT EXISTS idx_gifting_rules_trigger ON public.gifting_rules (trigger_kind, trigger_date);

DROP TRIGGER IF EXISTS trg_gifting_rules_updated_at ON public.gifting_rules;
CREATE TRIGGER trg_gifting_rules_updated_at
  BEFORE UPDATE ON public.gifting_rules
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- RLS

ALTER TABLE public.gifting_rules ENABLE ROW LEVEL SECURITY;

-- Corporate users can read their own corporate's rules
DROP POLICY IF EXISTS "Corporate members can read gifting_rules" ON public.gifting_rules;
CREATE POLICY "Corporate members can read gifting_rules" ON public.gifting_rules
  FOR SELECT
  USING (
    corporate_id IN (
      SELECT corporate_id FROM public.user_profiles WHERE id = auth.uid()
    )
  );

-- Only L3 admin (and mogzu_admin) can mutate
DROP POLICY IF EXISTS "L3 admin can manage gifting_rules" ON public.gifting_rules;
CREATE POLICY "L3 admin can manage gifting_rules" ON public.gifting_rules
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('l3_admin', 'mogzu_admin')
        AND p.corporate_id = gifting_rules.corporate_id
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('l3_admin', 'mogzu_admin')
        AND p.corporate_id = gifting_rules.corporate_id
    )
  );


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000005_role_switcher.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Role Switcher (Story 1.5) ───────────────────────────────────────────────
--
-- Allow a single user_profile to hold multiple roles (e.g. L2 Manager + L3 Admin
-- in the same corporate, or vendor + mogzu_admin during onboarding). The
-- profile's primary role stays in user_profiles.role; additional grants live in
-- available_roles[]. UI reads the union and lets the user pick an active role
-- per session.
--
-- Switches are audited in role_switch_events.

ALTER TABLE public.user_profiles
  ADD COLUMN IF NOT EXISTS available_roles TEXT[] DEFAULT '{}'::TEXT[];

CREATE TABLE IF NOT EXISTS public.role_switch_events (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  from_role TEXT NOT NULL,
  to_role TEXT NOT NULL,
  switched_at TIMESTAMPTZ DEFAULT NOW(),
  user_agent TEXT,
  ip_address TEXT
);

CREATE INDEX IF NOT EXISTS idx_role_switch_user_time ON public.role_switch_events (user_id, switched_at DESC);

ALTER TABLE public.role_switch_events ENABLE ROW LEVEL SECURITY;

-- User can read their own switches; mogzu_admin reads everything
DROP POLICY IF EXISTS "User can read own role_switch_events" ON public.role_switch_events;
CREATE POLICY "User can read own role_switch_events" ON public.role_switch_events
  FOR SELECT
  USING (
    user_id = auth.uid()
    OR EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  );

-- Only the acting user inserts their own switches
DROP POLICY IF EXISTS "User can log own role switches" ON public.role_switch_events;
CREATE POLICY "User can log own role switches" ON public.role_switch_events
  FOR INSERT
  WITH CHECK (user_id = auth.uid());


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000006_refunds.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Refunds (Story 6.3) ─────────────────────────────────────────────────────
--
-- Automated refund tracking on booking cancellation.
--
-- Wallet refunds are processed immediately by the app (credit wallet +
-- write a wallet_transactions row); the refunds row is inserted with
-- status='processed'. Card/UPI refunds are inserted with status='pending'
-- and wait for the Razorpay refund webhook to mark them processed.
--
-- If refund_status='failed' the supporting N8N workflow opens a support
-- ticket automatically (workflow lands in P1 7.3).

CREATE TABLE IF NOT EXISTS public.refunds (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id UUID NOT NULL REFERENCES public.bookings(id) ON DELETE CASCADE,
  corporate_id UUID NOT NULL REFERENCES public.corporate_accounts(id) ON DELETE CASCADE,
  amount NUMERIC(12, 2) NOT NULL CHECK (amount >= 0),
  method TEXT NOT NULL CHECK (method IN ('wallet', 'card', 'upi')),
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('pending', 'processed', 'failed')),
  gateway_reference TEXT,
  failure_reason TEXT,
  initiated_by UUID REFERENCES public.user_profiles(id),
  initiated_at TIMESTAMPTZ DEFAULT NOW(),
  processed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_refunds_booking ON public.refunds (booking_id);
CREATE INDEX IF NOT EXISTS idx_refunds_corp_status ON public.refunds (corporate_id, status);
CREATE INDEX IF NOT EXISTS idx_refunds_pending ON public.refunds (status) WHERE status = 'pending';

DROP TRIGGER IF EXISTS trg_refunds_updated_at ON public.refunds;
CREATE TRIGGER trg_refunds_updated_at
  BEFORE UPDATE ON public.refunds
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.refunds ENABLE ROW LEVEL SECURITY;

-- Corporate members read their own refunds; vendors read refunds for their bookings
DROP POLICY IF EXISTS "Corporate members read own refunds" ON public.refunds;
CREATE POLICY "Corporate members read own refunds" ON public.refunds
  FOR SELECT
  USING (
    corporate_id IN (
      SELECT corporate_id FROM public.user_profiles WHERE id = auth.uid()
    )
  );

DROP POLICY IF EXISTS "Vendor reads refunds for own bookings" ON public.refunds;
CREATE POLICY "Vendor reads refunds for own bookings" ON public.refunds
  FOR SELECT
  USING (
    booking_id IN (
      SELECT b.id
      FROM public.bookings b
      JOIN public.user_profiles p ON p.id = auth.uid()
      WHERE b.vendor_id = p.vendor_id
    )
  );

-- L3 admin / mogzu_admin can manage refunds; vendors can only initiate
-- (their booking rejection triggers a refund).
DROP POLICY IF EXISTS "L3 admin and mogzu_admin manage refunds" ON public.refunds;
CREATE POLICY "L3 admin and mogzu_admin manage refunds" ON public.refunds
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role IN ('l3_admin', 'mogzu_admin')
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role IN ('l3_admin', 'mogzu_admin')
    )
  );

DROP POLICY IF EXISTS "Vendor initiates refund on own booking" ON public.refunds;
CREATE POLICY "Vendor initiates refund on own booking" ON public.refunds
  FOR INSERT
  WITH CHECK (
    booking_id IN (
      SELECT b.id
      FROM public.bookings b
      JOIN public.user_profiles p ON p.id = auth.uid()
      WHERE b.vendor_id = p.vendor_id
    )
  );

DROP POLICY IF EXISTS "Booking owner initiates refund (self-cancel)" ON public.refunds;
CREATE POLICY "Booking owner initiates refund (self-cancel)" ON public.refunds
  FOR INSERT
  WITH CHECK (
    booking_id IN (
      SELECT id FROM public.bookings WHERE user_id = auth.uid()
    )
  );


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000007_payouts.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Vendor Payouts (Story 6.4) ──────────────────────────────────────────────
--
-- Vendor receives payout = booking.total_amount - (total * commission_rate),
-- scheduled 48 hours after booking.completed_at. An N8N workflow polls
-- payouts where status='scheduled' AND scheduled_for < now() AND
-- vendors.bank_account_verified=true, fires the bank transfer via Razorpay,
-- then flips status to 'processed'. Manual override available to
-- mogzu_admin (e.g. retry, hold pending KYC).
--
-- Statuses:
--   scheduled  — waiting for 48h to elapse + vendor bank verified.
--   processed  — money transferred; gateway_reference set.
--   held       — paused (KYC issue, dispute) with hold_reason explaining.
--   failed     — gateway rejected; admin retries or escalates.

CREATE TABLE IF NOT EXISTS public.payouts (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id UUID NOT NULL UNIQUE REFERENCES public.bookings(id) ON DELETE CASCADE,
  vendor_id UUID NOT NULL REFERENCES public.vendors(id) ON DELETE CASCADE,
  gross_amount NUMERIC(12, 2) NOT NULL CHECK (gross_amount >= 0),
  commission_amount NUMERIC(12, 2) NOT NULL DEFAULT 0,
  net_amount NUMERIC(12, 2) NOT NULL CHECK (net_amount >= 0),
  commission_rate NUMERIC(5, 4),
  status TEXT NOT NULL DEFAULT 'scheduled'
    CHECK (status IN ('scheduled', 'processed', 'held', 'failed')),
  scheduled_for TIMESTAMPTZ NOT NULL,
  processed_at TIMESTAMPTZ,
  gateway_reference TEXT,
  hold_reason TEXT,
  failure_reason TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_payouts_vendor_status ON public.payouts (vendor_id, status);
CREATE INDEX IF NOT EXISTS idx_payouts_due ON public.payouts (status, scheduled_for)
  WHERE status = 'scheduled';

DROP TRIGGER IF EXISTS trg_payouts_updated_at ON public.payouts;
CREATE TRIGGER trg_payouts_updated_at
  BEFORE UPDATE ON public.payouts
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.payouts ENABLE ROW LEVEL SECURITY;

-- Vendor reads own payouts
DROP POLICY IF EXISTS "Vendor reads own payouts" ON public.payouts;
CREATE POLICY "Vendor reads own payouts" ON public.payouts
  FOR SELECT
  USING (
    vendor_id IN (
      SELECT vendor_id FROM public.user_profiles WHERE id = auth.uid()
    )
  );

-- Mogzu admin reads everything + manages
DROP POLICY IF EXISTS "Mogzu admin manages payouts" ON public.payouts;
CREATE POLICY "Mogzu admin manages payouts" ON public.payouts
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  );

-- Booking completion (vendor self-mark or admin) inserts the schedule row.
DROP POLICY IF EXISTS "Vendor or admin inserts payout for own booking" ON public.payouts;
CREATE POLICY "Vendor or admin inserts payout for own booking" ON public.payouts
  FOR INSERT
  WITH CHECK (
    booking_id IN (
      SELECT b.id
      FROM public.bookings b
      JOIN public.user_profiles p ON p.id = auth.uid()
      WHERE b.vendor_id = p.vendor_id OR p.role = 'mogzu_admin'
    )
  );


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000008_employees.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Corporate Employee Directory (Story 10.0) ───────────────────────────────
--
-- Separate from user_profiles (which requires a Supabase auth user). L3 Admin
-- uploads CSV to seed celebration triggers + ICP for the gifting programme.
-- When an employee later signs up, user_profiles row links by email.
--
-- Used by 10.1 (celebration triggers) for DOB / join_date evaluation.

CREATE TABLE IF NOT EXISTS public.employees (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  corporate_id UUID NOT NULL REFERENCES public.corporate_accounts(id) ON DELETE CASCADE,
  email TEXT NOT NULL,
  full_name TEXT NOT NULL,
  department TEXT,
  role_hint TEXT,
  dob DATE,
  join_date DATE,
  phone TEXT,
  is_active BOOLEAN DEFAULT TRUE,
  imported_at TIMESTAMPTZ DEFAULT NOW(),
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (corporate_id, email)
);

CREATE INDEX IF NOT EXISTS idx_employees_corp ON public.employees (corporate_id, is_active);
CREATE INDEX IF NOT EXISTS idx_employees_dob ON public.employees (corporate_id, dob)
  WHERE dob IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_employees_join_date ON public.employees (corporate_id, join_date)
  WHERE join_date IS NOT NULL;

DROP TRIGGER IF EXISTS trg_employees_updated_at ON public.employees;
CREATE TRIGGER trg_employees_updated_at
  BEFORE UPDATE ON public.employees
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.employees ENABLE ROW LEVEL SECURITY;

-- Corporate members can read their corporate's employees
DROP POLICY IF EXISTS "Corporate members read own employees" ON public.employees;
CREATE POLICY "Corporate members read own employees" ON public.employees
  FOR SELECT
  USING (
    corporate_id IN (
      SELECT corporate_id FROM public.user_profiles WHERE id = auth.uid()
    )
  );

-- Only L3 admin / mogzu_admin can write
DROP POLICY IF EXISTS "L3 admin manages employees" ON public.employees;
CREATE POLICY "L3 admin manages employees" ON public.employees
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('l3_admin', 'mogzu_admin')
        AND p.corporate_id = employees.corporate_id
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('l3_admin', 'mogzu_admin')
        AND p.corporate_id = employees.corporate_id
    )
  );


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000009_notifications.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Notifications (Story 7.2) ───────────────────────────────────────────────
--
-- In-app notification feed + delivery preferences per user. Emails are
-- queued via email_status='queued' and processed by the future Resend
-- Edge Function / N8N (7.3). Critical types are emitted regardless of
-- preference; non-critical types respect user opt-out.

CREATE TYPE public.notification_type AS ENUM (
  'booking_confirmed',
  'booking_cancelled',
  'approval_required',
  'approval_decided',
  'payment_received',
  'payment_failed',
  'refund_initiated',
  'refund_failed',
  'reminder_24h',
  'gift_received',
  'gift_pending_approval',
  'support_reply',
  'system'
);

CREATE TABLE IF NOT EXISTS public.notifications (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  type public.notification_type NOT NULL,
  title TEXT NOT NULL,
  body TEXT,
  link_url TEXT,
  metadata JSONB DEFAULT '{}'::JSONB,
  is_read BOOLEAN DEFAULT FALSE,
  read_at TIMESTAMPTZ,
  email_status TEXT NOT NULL DEFAULT 'skipped'
    CHECK (email_status IN ('skipped', 'queued', 'sent', 'failed')),
  email_sent_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_notifications_user_unread ON public.notifications (user_id, is_read, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_notifications_email_queue ON public.notifications (email_status)
  WHERE email_status = 'queued';

ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "User reads own notifications" ON public.notifications;
CREATE POLICY "User reads own notifications" ON public.notifications
  FOR SELECT
  USING (user_id = auth.uid());

DROP POLICY IF EXISTS "User updates own notifications" ON public.notifications;
CREATE POLICY "User updates own notifications" ON public.notifications
  FOR UPDATE
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());

-- Anyone authenticated can insert notifications scoped to the recipient.
-- Cross-user notify happens server-side via RPC normally; for client
-- emit paths (approve/reject/cancel) the actor is authenticated and the
-- emit policy matches the actor's relationship with the user.
DROP POLICY IF EXISTS "Authenticated insert notification" ON public.notifications;
CREATE POLICY "Authenticated insert notification" ON public.notifications
  FOR INSERT
  WITH CHECK (auth.uid() IS NOT NULL);

-- ─── Notification Preferences ────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.notification_preferences (
  user_id UUID PRIMARY KEY REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  in_app_enabled_types public.notification_type[] DEFAULT ARRAY[
    'booking_confirmed','booking_cancelled','approval_required','approval_decided',
    'payment_received','payment_failed','refund_initiated','refund_failed',
    'reminder_24h','gift_received','gift_pending_approval','support_reply','system'
  ]::public.notification_type[],
  email_enabled_types public.notification_type[] DEFAULT ARRAY[
    'booking_confirmed','booking_cancelled','approval_decided',
    'payment_failed','refund_initiated','refund_failed','support_reply'
  ]::public.notification_type[],
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

DROP TRIGGER IF EXISTS trg_notification_preferences_updated_at ON public.notification_preferences;
CREATE TRIGGER trg_notification_preferences_updated_at
  BEFORE UPDATE ON public.notification_preferences
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.notification_preferences ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "User manages own preferences" ON public.notification_preferences;
CREATE POLICY "User manages own preferences" ON public.notification_preferences
  FOR ALL
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000010_support_tickets.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Support Tickets (Stories 12.1, 12.2, 12.3) ──────────────────────────────
--
-- Single tickets table with audience='corporate' | 'vendor' to split queues
-- visually but keep one schema. RLS:
--   - Submitter reads own
--   - Vendor reads own vendor-audience tickets
--   - Mogzu support / mogzu_admin reads everything
--   - Internal notes only readable to support roles

CREATE TYPE public.ticket_status AS ENUM (
  'open', 'in_progress', 'waiting_user', 'resolved', 'closed'
);

CREATE TYPE public.ticket_priority AS ENUM ('low', 'normal', 'high', 'urgent');

CREATE TYPE public.ticket_audience AS ENUM ('corporate', 'vendor');

CREATE TABLE IF NOT EXISTS public.support_tickets (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  audience public.ticket_audience NOT NULL DEFAULT 'corporate',
  submitter_id UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  corporate_id UUID REFERENCES public.corporate_accounts(id) ON DELETE SET NULL,
  vendor_id UUID REFERENCES public.vendors(id) ON DELETE SET NULL,
  category TEXT NOT NULL,
  subject TEXT NOT NULL,
  body TEXT NOT NULL,
  status public.ticket_status NOT NULL DEFAULT 'open',
  priority public.ticket_priority NOT NULL DEFAULT 'normal',
  sla_hours INTEGER NOT NULL DEFAULT 24,
  context_url TEXT,
  context_role TEXT,
  context_last_action TEXT,
  context_user_agent TEXT,
  assigned_to UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  related_booking_id UUID REFERENCES public.bookings(id) ON DELETE SET NULL,
  related_payout_id UUID REFERENCES public.payouts(id) ON DELETE SET NULL,
  csat_score INTEGER CHECK (csat_score BETWEEN 1 AND 5),
  csat_feedback TEXT,
  resolved_at TIMESTAMPTZ,
  closed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_support_submitter ON public.support_tickets (submitter_id, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_support_vendor ON public.support_tickets (vendor_id, status) WHERE vendor_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_support_corp ON public.support_tickets (corporate_id, status) WHERE corporate_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_support_queue ON public.support_tickets (status, priority, created_at);

DROP TRIGGER IF EXISTS trg_support_tickets_updated_at ON public.support_tickets;
CREATE TRIGGER trg_support_tickets_updated_at
  BEFORE UPDATE ON public.support_tickets
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.support_tickets ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Submitter reads own ticket" ON public.support_tickets;
CREATE POLICY "Submitter reads own ticket" ON public.support_tickets
  FOR SELECT
  USING (submitter_id = auth.uid());

DROP POLICY IF EXISTS "Submitter inserts own ticket" ON public.support_tickets;
CREATE POLICY "Submitter inserts own ticket" ON public.support_tickets
  FOR INSERT
  WITH CHECK (submitter_id = auth.uid());

DROP POLICY IF EXISTS "Submitter updates own ticket fields" ON public.support_tickets;
CREATE POLICY "Submitter updates own ticket fields" ON public.support_tickets
  FOR UPDATE
  USING (submitter_id = auth.uid())
  WITH CHECK (submitter_id = auth.uid());

DROP POLICY IF EXISTS "Support roles manage all tickets" ON public.support_tickets;
CREATE POLICY "Support roles manage all tickets" ON public.support_tickets
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  );

-- ─── Ticket Notes ─────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.support_ticket_notes (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  ticket_id UUID NOT NULL REFERENCES public.support_tickets(id) ON DELETE CASCADE,
  author_id UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  body TEXT NOT NULL,
  is_internal BOOLEAN NOT NULL DEFAULT FALSE,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_ticket_notes_ticket ON public.support_ticket_notes (ticket_id, created_at);

ALTER TABLE public.support_ticket_notes ENABLE ROW LEVEL SECURITY;

-- Submitter reads non-internal notes on their tickets
DROP POLICY IF EXISTS "Submitter reads public notes" ON public.support_ticket_notes;
CREATE POLICY "Submitter reads public notes" ON public.support_ticket_notes
  FOR SELECT
  USING (
    NOT is_internal
    AND ticket_id IN (
      SELECT id FROM public.support_tickets WHERE submitter_id = auth.uid()
    )
  );

-- Submitter can post a reply (always public)
DROP POLICY IF EXISTS "Submitter posts reply" ON public.support_ticket_notes;
CREATE POLICY "Submitter posts reply" ON public.support_ticket_notes
  FOR INSERT
  WITH CHECK (
    author_id = auth.uid()
    AND is_internal = FALSE
    AND ticket_id IN (
      SELECT id FROM public.support_tickets WHERE submitter_id = auth.uid()
    )
  );

-- Support roles read/write all notes (including internal)
DROP POLICY IF EXISTS "Support roles manage all notes" ON public.support_ticket_notes;
CREATE POLICY "Support roles manage all notes" ON public.support_ticket_notes
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  );


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000011_celebration_events.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Celebration Events (Stories 10.1, 10.2) ─────────────────────────────────
--
-- One row per scheduled milestone gift per employee. N8N daily cron computes
-- the next 30 days of birthdays / work anniversaries from employees.dob /
-- employees.join_date matched against gifting_rules with trigger_kind in
-- ('birthday','work_anniversary'). Fixed-date rules (Diwali etc) bulk-insert
-- one row per active employee.
--
-- Lifecycle:
--   scheduled    — automated default will fire at trigger_date.
--   personalised — manager edited message / variant / budget; will fire.
--   suppressed   — manager marked "done externally"; will not fire.
--   fired        — celebration gift booking created (booking_id set).
--   failed       — fire attempt failed (e.g. wallet short); manual retry.

CREATE TYPE public.celebration_status AS ENUM (
  'scheduled', 'personalised', 'suppressed', 'fired', 'failed'
);

CREATE TABLE IF NOT EXISTS public.celebration_events (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  corporate_id UUID NOT NULL REFERENCES public.corporate_accounts(id) ON DELETE CASCADE,
  gifting_rule_id UUID NOT NULL REFERENCES public.gifting_rules(id) ON DELETE CASCADE,
  employee_id UUID NOT NULL REFERENCES public.employees(id) ON DELETE CASCADE,
  manager_id UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  occasion_name TEXT NOT NULL,
  trigger_date DATE NOT NULL,
  status public.celebration_status NOT NULL DEFAULT 'scheduled',
  default_listing_id UUID REFERENCES public.listings(id) ON DELETE SET NULL,
  listing_id_override UUID REFERENCES public.listings(id) ON DELETE SET NULL,
  budget_override NUMERIC(12, 2),
  manager_message TEXT,
  personalised_at TIMESTAMPTZ,
  suppressed_at TIMESTAMPTZ,
  suppressed_reason TEXT,
  fired_booking_id UUID REFERENCES public.bookings(id) ON DELETE SET NULL,
  fired_at TIMESTAMPTZ,
  failure_reason TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (corporate_id, gifting_rule_id, employee_id, trigger_date)
);

CREATE INDEX IF NOT EXISTS idx_celebrations_corp_date ON public.celebration_events (corporate_id, trigger_date);
CREATE INDEX IF NOT EXISTS idx_celebrations_manager_pending ON public.celebration_events (manager_id, status)
  WHERE status IN ('scheduled', 'personalised');
CREATE INDEX IF NOT EXISTS idx_celebrations_due ON public.celebration_events (status, trigger_date)
  WHERE status IN ('scheduled', 'personalised');

DROP TRIGGER IF EXISTS trg_celebration_events_updated_at ON public.celebration_events;
CREATE TRIGGER trg_celebration_events_updated_at
  BEFORE UPDATE ON public.celebration_events
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.celebration_events ENABLE ROW LEVEL SECURITY;

-- Corporate members can read their corporate's celebrations
DROP POLICY IF EXISTS "Corporate members read own celebrations" ON public.celebration_events;
CREATE POLICY "Corporate members read own celebrations" ON public.celebration_events
  FOR SELECT
  USING (
    corporate_id IN (
      SELECT corporate_id FROM public.user_profiles WHERE id = auth.uid()
    )
  );

-- L3 admin / mogzu_admin / account_manager manage everything in scope
DROP POLICY IF EXISTS "L3 admin manages celebrations" ON public.celebration_events;
CREATE POLICY "L3 admin manages celebrations" ON public.celebration_events
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND (
          p.role IN ('mogzu_admin', 'account_manager')
          OR (p.role = 'l3_admin' AND p.corporate_id = celebration_events.corporate_id)
        )
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND (
          p.role IN ('mogzu_admin', 'account_manager')
          OR (p.role = 'l3_admin' AND p.corporate_id = celebration_events.corporate_id)
        )
    )
  )

-- L2 manager can personalise / suppress events where they are the manager
;
DROP POLICY IF EXISTS "L2 manager personalises own team celebrations" ON public.celebration_events;
CREATE POLICY "L2 manager personalises own team celebrations" ON public.celebration_events
  FOR UPDATE
  USING (
    manager_id = auth.uid()
    AND EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'l2_manager'
    )
  )
  WITH CHECK (
    manager_id = auth.uid()
    AND EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'l2_manager'
    )
  );


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000012_travel_and_tracking.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Travel & Space Policy (Story 5.5) ──────────────────────────────────────
--
-- L3 Admin defines policy tiers per role. Stay/space search enforces by
-- filtering or flagging results above max_nightly_rate or outside
-- approved_cities, and requires bookings to be initiated at least
-- min_lead_days in advance.

CREATE TABLE IF NOT EXISTS public.travel_policies (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  corporate_id UUID NOT NULL REFERENCES public.corporate_accounts(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  role_tier TEXT NOT NULL CHECK (role_tier IN ('l1_employee', 'l2_manager', 'l3_admin', 'all')),
  max_nightly_rate NUMERIC(12, 2) NOT NULL CHECK (max_nightly_rate > 0),
  approved_cities TEXT[] DEFAULT '{}'::TEXT[],
  min_lead_days INTEGER NOT NULL DEFAULT 0,
  module TEXT NOT NULL DEFAULT 'spacex_stay'
    CHECK (module IN ('spacex_stay', 'spacex_coworking')),
  is_active BOOLEAN DEFAULT TRUE,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_travel_policies_corp ON public.travel_policies (corporate_id, role_tier, is_active);

DROP TRIGGER IF EXISTS trg_travel_policies_updated_at ON public.travel_policies;
CREATE TRIGGER trg_travel_policies_updated_at
  BEFORE UPDATE ON public.travel_policies
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.travel_policies ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Corporate members read own policies" ON public.travel_policies;
CREATE POLICY "Corporate members read own policies" ON public.travel_policies
  FOR SELECT
  USING (
    corporate_id IN (
      SELECT corporate_id FROM public.user_profiles WHERE id = auth.uid()
    )
  );

DROP POLICY IF EXISTS "L3 admin manages own policies" ON public.travel_policies;
CREATE POLICY "L3 admin manages own policies" ON public.travel_policies
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('l3_admin', 'mogzu_admin')
        AND p.corporate_id = travel_policies.corporate_id
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('l3_admin', 'mogzu_admin')
        AND p.corporate_id = travel_policies.corporate_id
    )
  );

-- ─── Gift Delivery Tracking (Story 4.6) ───────────────────────────────────────
--
-- Extends bookings with a fulfilment_stage for gifting orders and optional
-- carrier tracking details. Stage transitions emit notifications via the
-- shared notify helper (handled in the React app, future N8N once webhooks
-- from carriers land).

ALTER TABLE public.bookings
  ADD COLUMN IF NOT EXISTS fulfilment_stage TEXT
    CHECK (fulfilment_stage IN (
      'ordered', 'packed', 'dispatched', 'out_for_delivery', 'delivered', 'returned'
    )),
  ADD COLUMN IF NOT EXISTS tracking_number TEXT,
  ADD COLUMN IF NOT EXISTS carrier TEXT,
  ADD COLUMN IF NOT EXISTS carrier_url TEXT;

CREATE INDEX IF NOT EXISTS idx_bookings_fulfilment
  ON public.bookings (module, fulfilment_stage)
  WHERE module = 'gifting';


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000013_messages_disputes.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Booking Messages (Story 7.1) ────────────────────────────────────────────
--
-- One thread per booking. Corporate user, vendor, and (for disputes) Mogzu
-- support can all post. Real-time via Supabase Realtime channel on the
-- booking_messages filter `booking_id=eq.<id>`. Attachments are stored in
-- the `support-evidence` bucket (or shared `vendor-images` for now) and
-- referenced as { url, name, size } objects in the attachments JSONB.

CREATE TABLE IF NOT EXISTS public.booking_messages (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id UUID NOT NULL REFERENCES public.bookings(id) ON DELETE CASCADE,
  sender_id UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  body TEXT NOT NULL,
  attachments JSONB NOT NULL DEFAULT '[]'::JSONB,
  read_by UUID[] NOT NULL DEFAULT '{}'::UUID[],
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_booking_messages_thread ON public.booking_messages (booking_id, created_at);

ALTER TABLE public.booking_messages ENABLE ROW LEVEL SECURITY;

-- Booking participants (booker + vendor staff) and support roles can read.
DROP POLICY IF EXISTS "Booking participants read messages" ON public.booking_messages;
CREATE POLICY "Booking participants read messages" ON public.booking_messages
  FOR SELECT
  USING (
    booking_id IN (
      SELECT b.id
      FROM public.bookings b
      LEFT JOIN public.user_profiles p ON p.id = auth.uid()
      WHERE b.user_id = auth.uid()
         OR b.vendor_id = p.vendor_id
         OR p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  );

-- Same set can insert. sender_id must be auth.uid().
DROP POLICY IF EXISTS "Booking participants post messages" ON public.booking_messages;
CREATE POLICY "Booking participants post messages" ON public.booking_messages
  FOR INSERT
  WITH CHECK (
    sender_id = auth.uid()
    AND booking_id IN (
      SELECT b.id
      FROM public.bookings b
      LEFT JOIN public.user_profiles p ON p.id = auth.uid()
      WHERE b.user_id = auth.uid()
         OR b.vendor_id = p.vendor_id
         OR p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  );

-- Sender can update own message read_by (mark-as-read).
DROP POLICY IF EXISTS "Recipient updates read_by" ON public.booking_messages;
CREATE POLICY "Recipient updates read_by" ON public.booking_messages
  FOR UPDATE
  USING (
    booking_id IN (
      SELECT b.id
      FROM public.bookings b
      LEFT JOIN public.user_profiles p ON p.id = auth.uid()
      WHERE b.user_id = auth.uid() OR b.vendor_id = p.vendor_id
    )
  )
  WITH CHECK (TRUE);

-- ─── Booking Disputes (Story 9.5) ────────────────────────────────────────────

CREATE TYPE public.dispute_status AS ENUM (
  'open', 'investigating', 'awaiting_party', 'resolved', 'dismissed'
);

CREATE TYPE public.dispute_resolution AS ENUM (
  'no_refund', 'partial_refund', 'full_refund', 'vendor_penalty', 'no_action'
);

CREATE TABLE IF NOT EXISTS public.booking_disputes (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id UUID NOT NULL REFERENCES public.bookings(id) ON DELETE CASCADE,
  raised_by UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  reason_category TEXT NOT NULL,
  reason_body TEXT NOT NULL,
  status public.dispute_status NOT NULL DEFAULT 'open',
  evidence_urls TEXT[] DEFAULT '{}'::TEXT[],
  resolution public.dispute_resolution,
  resolution_note TEXT,
  resolved_by UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  resolved_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_booking_disputes_status ON public.booking_disputes (status, created_at);
CREATE INDEX IF NOT EXISTS idx_booking_disputes_booking ON public.booking_disputes (booking_id);

DROP TRIGGER IF EXISTS trg_booking_disputes_updated_at ON public.booking_disputes;
CREATE TRIGGER trg_booking_disputes_updated_at
  BEFORE UPDATE ON public.booking_disputes
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.booking_disputes ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Booking participants read disputes" ON public.booking_disputes;
CREATE POLICY "Booking participants read disputes" ON public.booking_disputes
  FOR SELECT
  USING (
    booking_id IN (
      SELECT b.id
      FROM public.bookings b
      LEFT JOIN public.user_profiles p ON p.id = auth.uid()
      WHERE b.user_id = auth.uid()
         OR b.vendor_id = p.vendor_id
         OR p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  );

DROP POLICY IF EXISTS "Booking participants raise dispute" ON public.booking_disputes;
CREATE POLICY "Booking participants raise dispute" ON public.booking_disputes
  FOR INSERT
  WITH CHECK (
    raised_by = auth.uid()
    AND booking_id IN (
      SELECT b.id
      FROM public.bookings b
      LEFT JOIN public.user_profiles p ON p.id = auth.uid()
      WHERE b.user_id = auth.uid() OR b.vendor_id = p.vendor_id
    )
  );

DROP POLICY IF EXISTS "Support roles manage disputes" ON public.booking_disputes;
CREATE POLICY "Support roles manage disputes" ON public.booking_disputes
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('support', 'mogzu_admin', 'account_manager')
    )
  );


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000014_gifting_campaigns.sql
-- ════════════════════════════════════════════════════════════════════════

-- ─── Bulk Gifting Campaigns (Story 4.3) ─────────────────────────────────────
--
-- L3 Admin runs a bulk gifting campaign: picks an occasion, a gifting product,
-- and a recipient scope (all employees / department / custom employee list).
-- System creates one bookings row per recipient and links them under a
-- gifting_campaigns parent row. Vendor sees individual orders in their
-- existing queue but with a campaign_id reference for grouping.

CREATE TABLE IF NOT EXISTS public.gifting_campaigns (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  corporate_id UUID NOT NULL REFERENCES public.corporate_accounts(id) ON DELETE CASCADE,
  occasion_name TEXT NOT NULL,
  listing_id UUID NOT NULL REFERENCES public.listings(id) ON DELETE CASCADE,
  scope TEXT NOT NULL CHECK (scope IN ('all', 'department', 'custom')),
  scope_value TEXT,
  message TEXT,
  budget_per_recipient NUMERIC(12, 2) NOT NULL,
  recipient_count INTEGER NOT NULL,
  total_budget NUMERIC(12, 2) NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending_vendor'
    CHECK (status IN ('draft', 'pending_vendor', 'in_progress', 'completed', 'cancelled')),
  created_by UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_gifting_campaigns_corp ON public.gifting_campaigns (corporate_id, status);

DROP TRIGGER IF EXISTS trg_gifting_campaigns_updated_at ON public.gifting_campaigns;
CREATE TRIGGER trg_gifting_campaigns_updated_at
  BEFORE UPDATE ON public.gifting_campaigns
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.gifting_campaigns ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Corporate members read own campaigns" ON public.gifting_campaigns;
CREATE POLICY "Corporate members read own campaigns" ON public.gifting_campaigns
  FOR SELECT
  USING (
    corporate_id IN (
      SELECT corporate_id FROM public.user_profiles WHERE id = auth.uid()
    )
  );

DROP POLICY IF EXISTS "L3 admin manages campaigns" ON public.gifting_campaigns;
CREATE POLICY "L3 admin manages campaigns" ON public.gifting_campaigns
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('l3_admin', 'mogzu_admin')
        AND p.corporate_id = gifting_campaigns.corporate_id
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('l3_admin', 'mogzu_admin')
        AND p.corporate_id = gifting_campaigns.corporate_id
    )
  );

-- Link bookings to campaigns so the admin can drill into per-employee fulfilment.
ALTER TABLE public.bookings
  ADD COLUMN IF NOT EXISTS gifting_campaign_id UUID REFERENCES public.gifting_campaigns(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_bookings_campaign
  ON public.bookings (gifting_campaign_id)
  WHERE gifting_campaign_id IS NOT NULL;


