DROP POLICY IF EXISTS "Vendor manages own promotions" ON public.promotions;
CREATE POLICY "Vendor manages own promotions" ON public.promotions
  FOR ALL
  USING (
    vendor_id IN (
      SELECT vendor_id FROM public.user_profiles WHERE id = auth.uid()
