  BEFORE UPDATE ON public.heygenie_config
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.heygenie_config ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Corporate members read own heygenie_config" ON public.heygenie_config;
CREATE POLICY "Corporate members read own heygenie_config" ON public.heygenie_config
  FOR SELECT
  USING (
    corporate_id IN (
