    )
  );

DROP POLICY IF EXISTS "Mogzu admin manages heygenie_config" ON public.heygenie_config;
CREATE POLICY "Mogzu admin manages heygenie_config" ON public.heygenie_config
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  );

CREATE TABLE IF NOT EXISTS public.heygenie_sessions (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  corporate_id UUID NOT NULL REFERENCES public.corporate_accounts(id) ON DELETE CASCADE,
  transcript TEXT NOT NULL,
  intent JSONB,
  resulting_booking_id UUID REFERENCES public.bookings(id) ON DELETE SET NULL,
