CREATE INDEX IF NOT EXISTS idx_heygenie_sessions_user ON public.heygenie_sessions (user_id, created_at DESC);

ALTER TABLE public.heygenie_sessions ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "User reads + inserts own heygenie sessions" ON public.heygenie_sessions;
CREATE POLICY "User reads + inserts own heygenie sessions" ON public.heygenie_sessions
  FOR ALL
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());

DROP POLICY IF EXISTS "Mogzu admin reads all heygenie sessions" ON public.heygenie_sessions;
CREATE POLICY "Mogzu admin reads all heygenie sessions" ON public.heygenie_sessions
  FOR SELECT
  USING (
