-- ════════════════════════════════════════════════════════════════════════
-- 20260516000018_partners.sql
-- ════════════════════════════════════════════════════════════════════════

-- Sprint 19 — Partner Foundation (Stories 14.1, 14.6, 14.2)
--
-- Partners are independent referrers / resellers who bring corporate clients
-- to the platform. This migration models the partner identity, the rate
-- agreements admin configures per partner, the per-corporate referral
-- attribution window, and a dedicated partner wallet for commission credits.

-- ─── Partners ────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.partners (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id UUID UNIQUE REFERENCES auth.users(id) ON DELETE SET NULL,
  partner_type TEXT NOT NULL DEFAULT 'consultant' CHECK (
    partner_type IN ('consultant', 'agency', 'reseller', 'freelancer')
  ),
  status TEXT NOT NULL DEFAULT 'pending' CHECK (
    status IN ('pending', 'active', 'paused', 'terminated', 'rejected')
  ),
  full_name TEXT NOT NULL,
  email TEXT NOT NULL,
  phone TEXT,
  business_name TEXT,
  expertise TEXT[] NOT NULL DEFAULT '{}'::TEXT[],
  referral_code TEXT UNIQUE,
  bank_account_name TEXT,
  bank_account_number TEXT,
  bank_ifsc TEXT,
  approved_by UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  approved_at TIMESTAMPTZ,
  rejection_reason TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_partners_status ON public.partners (status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_partners_referral_code ON public.partners (referral_code);

DROP TRIGGER IF EXISTS trg_partners_updated_at ON public.partners;
CREATE TRIGGER trg_partners_updated_at
  BEFORE UPDATE ON public.partners
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.partners ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Partner reads own row" ON public.partners;
CREATE POLICY "Partner reads own row" ON public.partners
  FOR SELECT
  USING (user_id = auth.uid());

DROP POLICY IF EXISTS "Partner updates own non-status fields" ON public.partners;
CREATE POLICY "Partner updates own non-status fields" ON public.partners
  FOR UPDATE
  USING (user_id = auth.uid())
  WITH CHECK (user_id = auth.uid());

DROP POLICY IF EXISTS "Admin manages all partners" ON public.partners;
CREATE POLICY "Admin manages all partners" ON public.partners
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role IN ('mogzu_admin', 'support')
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role IN ('mogzu_admin', 'support')
    )
  );

DROP POLICY IF EXISTS "Public insert pending partner signup" ON public.partners;
CREATE POLICY "Public insert pending partner signup" ON public.partners
  FOR INSERT
  WITH CHECK (status = 'pending');

-- ─── Partner Agreements (Story 14.6) ─────────────────────────────────────────
--
-- Versioned rate sheet per partner. is_current is maintained by trigger so
-- there is always at most one current agreement per partner.

CREATE TABLE IF NOT EXISTS public.partner_agreements (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  partner_id UUID NOT NULL REFERENCES public.partners(id) ON DELETE CASCADE,
  referral_pct NUMERIC(5, 2) NOT NULL DEFAULT 0
    CHECK (referral_pct >= 0 AND referral_pct <= 100),
  reseller_wholesale_pct NUMERIC(5, 2) NOT NULL DEFAULT 0
    CHECK (reseller_wholesale_pct >= 0 AND reseller_wholesale_pct <= 100),
  product_revenue_share_pct NUMERIC(5, 2) NOT NULL DEFAULT 0
    CHECK (product_revenue_share_pct >= 0 AND product_revenue_share_pct <= 100),
  valid_from TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  expires_at TIMESTAMPTZ,
  configured_by UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  notes TEXT,
  is_current BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_partner_agreements_partner ON public.partner_agreements (partner_id, is_current, valid_from DESC);
CREATE UNIQUE INDEX IF NOT EXISTS uniq_partner_agreements_current
  ON public.partner_agreements (partner_id)
  WHERE is_current = TRUE;

CREATE OR REPLACE FUNCTION public.partner_agreement_set_current()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.is_current THEN
    UPDATE public.partner_agreements
       SET is_current = FALSE
     WHERE partner_id = NEW.partner_id
       AND id <> NEW.id
       AND is_current = TRUE;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_partner_agreement_set_current ON public.partner_agreements;
CREATE TRIGGER trg_partner_agreement_set_current
  AFTER INSERT ON public.partner_agreements
  FOR EACH ROW EXECUTE FUNCTION public.partner_agreement_set_current();

ALTER TABLE public.partner_agreements ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Partner reads own agreements" ON public.partner_agreements;
CREATE POLICY "Partner reads own agreements" ON public.partner_agreements
  FOR SELECT
  USING (
    partner_id IN (SELECT id FROM public.partners WHERE user_id = auth.uid())
  );

DROP POLICY IF EXISTS "Admin manages partner agreements" ON public.partner_agreements;
CREATE POLICY "Admin manages partner agreements" ON public.partner_agreements
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  );

-- ─── Corporate referral attribution ──────────────────────────────────────────
--
-- First-touch model: the partner code captured at signup is stored on the
-- corporate_account; the partner_referrals row records the lifecycle.

ALTER TABLE public.corporate_accounts
  ADD COLUMN IF NOT EXISTS referred_by_partner_id UUID REFERENCES public.partners(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS referred_at TIMESTAMPTZ;

CREATE INDEX IF NOT EXISTS idx_corporate_accounts_referred_partner
