CREATE INDEX IF NOT EXISTS idx_partner_referrals_partner ON public.partner_referrals (partner_id, signed_up_at DESC);

ALTER TABLE public.partner_referrals ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Partner reads own referrals" ON public.partner_referrals;
CREATE POLICY "Partner reads own referrals" ON public.partner_referrals
  FOR SELECT
  USING (
    partner_id IN (SELECT id FROM public.partners WHERE user_id = auth.uid())
  );

DROP POLICY IF EXISTS "Admin reads + writes all referrals" ON public.partner_referrals;
CREATE POLICY "Admin reads + writes all referrals" ON public.partner_referrals
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
