DROP POLICY IF EXISTS "Authenticated user inserts referral for own corporate" ON public.partner_referrals;
CREATE POLICY "Authenticated user inserts referral for own corporate" ON public.partner_referrals
  FOR INSERT
  WITH CHECK (
    referred_corporate_id IN (
      SELECT corporate_id FROM public.user_profiles WHERE id = auth.uid()
