    partner_id IN (SELECT id FROM public.partners WHERE user_id = auth.uid())
  );

DROP POLICY IF EXISTS "Admin manages partner wallet transactions" ON public.partner_wallet_transactions;
CREATE POLICY "Admin manages partner wallet transactions" ON public.partner_wallet_transactions
  FOR ALL
