-- 20260516000019_partner_advanced.sql
-- ════════════════════════════════════════════════════════════════════════

-- Sprint 20 — Partner Advanced: Resell + Own Listings (Stories 14.3, 14.4)
--
-- Adds the listing ownership split (vendor vs partner), the per-booking
-- partner markup capture, and the monthly partner payout reconciliation
-- table. Partner-onboarded clients are tracked via the existing
-- corporate_accounts.referred_by_partner_id from Sprint 19.

-- ─── partners: default markup ────────────────────────────────────────────────

ALTER TABLE public.partners
  ADD COLUMN IF NOT EXISTS default_markup_pct NUMERIC(5, 2) NOT NULL DEFAULT 0
    CHECK (default_markup_pct >= 0 AND default_markup_pct <= 30);

-- ─── listings: ownership split ───────────────────────────────────────────────

ALTER TABLE public.listings DROP CONSTRAINT IF EXISTS listings_owner_exclusive;
ALTER TABLE public.listings
  ALTER COLUMN vendor_id DROP NOT NULL,
  ADD COLUMN IF NOT EXISTS owner_type TEXT NOT NULL DEFAULT 'vendor'
    CHECK (owner_type IN ('vendor', 'partner')),
  ADD COLUMN IF NOT EXISTS owner_partner_id UUID REFERENCES public.partners(id) ON DELETE CASCADE,
  ADD CONSTRAINT listings_owner_exclusive CHECK (
    (owner_type = 'vendor' AND vendor_id IS NOT NULL AND owner_partner_id IS NULL)
    OR (owner_type = 'partner' AND owner_partner_id IS NOT NULL AND vendor_id IS NULL)
  );

CREATE INDEX IF NOT EXISTS idx_listings_partner_owner
  ON public.listings (owner_partner_id, status)
  WHERE owner_type = 'partner';

-- RLS: partner manages own listings; existing vendor + admin policies stay.
DROP POLICY IF EXISTS "Partner manages own listings" ON public.listings;
CREATE POLICY "Partner manages own listings" ON public.listings
  FOR ALL
  USING (
    owner_type = 'partner'
    AND owner_partner_id IN (
      SELECT id FROM public.partners WHERE user_id = auth.uid()
    )
  )
  WITH CHECK (
    owner_type = 'partner'
    AND owner_partner_id IN (
      SELECT id FROM public.partners WHERE user_id = auth.uid()
    )
  );

-- ─── bookings: partner resale fields ─────────────────────────────────────────

ALTER TABLE public.bookings
  ADD COLUMN IF NOT EXISTS partner_id UUID REFERENCES public.partners(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS partner_markup_pct NUMERIC(5, 2)
    CHECK (partner_markup_pct IS NULL OR (partner_markup_pct >= 0 AND partner_markup_pct <= 30)),
  ADD COLUMN IF NOT EXISTS partner_margin_amount NUMERIC(12, 2),
  ADD COLUMN IF NOT EXISTS partner_invoice_token TEXT UNIQUE,
  ADD COLUMN IF NOT EXISTS payout_accrued_at TIMESTAMPTZ;

CREATE INDEX IF NOT EXISTS idx_bookings_partner
  ON public.bookings (partner_id, status, created_at DESC)
  WHERE partner_id IS NOT NULL;

-- Allow public read of bookings via partner_invoice_token so that the
-- shareable white-label invoice link works without auth. Token is a random
-- 24-char slug; treat it as a bearer credential.
DROP POLICY IF EXISTS "Anyone can read booking via invoice token" ON public.bookings;
CREATE POLICY "Anyone can read booking via invoice token" ON public.bookings
  FOR SELECT
  USING (partner_invoice_token IS NOT NULL);

-- ─── partner_payout_periods ──────────────────────────────────────────────────
--
-- One row per partner per calendar month. Aggregates the margin / revenue
-- share that accrued during the period. Admin reconciles by marking paid;
-- the accompanying partner_wallet_transactions row records the payout.

CREATE TABLE IF NOT EXISTS public.partner_payout_periods (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  partner_id UUID NOT NULL REFERENCES public.partners(id) ON DELETE CASCADE,
  period_yyyymm TEXT NOT NULL,
  resale_margin NUMERIC(12, 2) NOT NULL DEFAULT 0,
  product_share NUMERIC(12, 2) NOT NULL DEFAULT 0,
  total_amount NUMERIC(12, 2) NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'paid', 'on_hold')),
  paid_at TIMESTAMPTZ,
  paid_by UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  payout_transaction_id UUID REFERENCES public.partner_wallet_transactions(id) ON DELETE SET NULL,
  note TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (partner_id, period_yyyymm)
);

CREATE INDEX IF NOT EXISTS idx_partner_payout_periods_status
  ON public.partner_payout_periods (status, period_yyyymm DESC);

DROP TRIGGER IF EXISTS trg_partner_payout_periods_updated_at ON public.partner_payout_periods;
CREATE TRIGGER trg_partner_payout_periods_updated_at
  BEFORE UPDATE ON public.partner_payout_periods
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.partner_payout_periods ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Partner reads own payout periods" ON public.partner_payout_periods;
CREATE POLICY "Partner reads own payout periods" ON public.partner_payout_periods
  FOR SELECT
  USING (
    partner_id IN (SELECT id FROM public.partners WHERE user_id = auth.uid())
  );

DROP POLICY IF EXISTS "Admin manages partner payout periods" ON public.partner_payout_periods;
CREATE POLICY "Admin manages partner payout periods" ON public.partner_payout_periods
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  );

-- ─── accrue_partner_earnings ─────────────────────────────────────────────────
--
-- Idempotent helper called when a booking transitions to 'completed'. Adds:
--   • resale margin (partner_margin_amount) when the booking has a partner_id
--   • product revenue share when the listing is partner-owned, computed from
--     the current partner agreement
-- into the partner_payout_periods row for the YYYYMM of the booking's
-- completion. Both contributions are guarded so re-running has no effect.

CREATE OR REPLACE FUNCTION public.accrue_partner_earnings(p_booking_id UUID)
RETURNS UUID AS $$
DECLARE
  v_booking RECORD;
  v_listing RECORD;
  v_period TEXT;
  v_period_id UUID;
  v_resale NUMERIC(12, 2) := 0;
  v_share NUMERIC(12, 2) := 0;
  v_partner_id UUID;
  v_agreement RECORD;
BEGIN
  SELECT * INTO v_booking FROM public.bookings
   WHERE id = p_booking_id AND status = 'completed';
  IF NOT FOUND THEN RETURN NULL; END IF;

  SELECT owner_type, owner_partner_id INTO v_listing
    FROM public.listings WHERE id = v_booking.listing_id;

  IF v_booking.partner_id IS NOT NULL THEN
    v_partner_id := v_booking.partner_id;
    v_resale := COALESCE(v_booking.partner_margin_amount, 0);
  ELSIF v_listing.owner_type = 'partner' THEN
    v_partner_id := v_listing.owner_partner_id;
  END IF;

  IF v_partner_id IS NULL THEN RETURN NULL; END IF;

  IF v_listing.owner_type = 'partner' THEN
    SELECT * INTO v_agreement
      FROM public.partner_agreements
     WHERE partner_id = v_partner_id AND is_current = TRUE
     LIMIT 1;
    IF FOUND AND v_agreement.product_revenue_share_pct > 0 THEN
      v_share := ROUND(
        COALESCE(v_booking.total_amount, 0) * v_agreement.product_revenue_share_pct / 100,
        2
      );
    END IF;
  END IF;

  IF v_resale = 0 AND v_share = 0 THEN RETURN NULL; END IF;

  v_period := to_char(COALESCE(v_booking.completed_at, NOW()), 'YYYYMM');

  INSERT INTO public.partner_payout_periods (partner_id, period_yyyymm)
  VALUES (v_partner_id, v_period)
  ON CONFLICT (partner_id, period_yyyymm) DO NOTHING;

  SELECT id INTO v_period_id FROM public.partner_payout_periods
   WHERE partner_id = v_partner_id AND period_yyyymm = v_period;

  -- Idempotency: only accrue if no payout_period_credit row exists for this
  -- booking yet. We use a small ledger embedded in the booking metadata.
  IF (v_booking.payout_accrued_at IS NULL) THEN
    UPDATE public.partner_payout_periods
       SET resale_margin = resale_margin + v_resale,
           product_share = product_share + v_share,
           total_amount = total_amount + v_resale + v_share
     WHERE id = v_period_id;
    UPDATE public.bookings
       SET payout_accrued_at = NOW()
     WHERE id = p_booking_id;
  END IF;

  RETURN v_period_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

GRANT EXECUTE ON FUNCTION public.accrue_partner_earnings(UUID) TO authenticated;

-- ─── mark_partner_payout_paid ────────────────────────────────────────────────

CREATE OR REPLACE FUNCTION public.mark_partner_payout_paid(
  p_period_id UUID,
  p_admin_id UUID,
  p_note TEXT DEFAULT NULL
) RETURNS UUID AS $$
DECLARE
  v_period RECORD;
  v_wallet_id UUID;
  v_tx_id UUID;
BEGIN
  SELECT * INTO v_period FROM public.partner_payout_periods
   WHERE id = p_period_id AND status = 'pending';
  IF NOT FOUND THEN RETURN NULL; END IF;
  IF v_period.total_amount <= 0 THEN RETURN NULL; END IF;

  SELECT id INTO v_wallet_id FROM public.partner_wallets
   WHERE partner_id = v_period.partner_id;
  IF v_wallet_id IS NULL THEN
    INSERT INTO public.partner_wallets (partner_id)
    VALUES (v_period.partner_id) RETURNING id INTO v_wallet_id;
  END IF;

  INSERT INTO public.partner_wallet_transactions (
    partner_wallet_id, partner_id, type, amount, description
  ) VALUES (
    v_wallet_id, v_period.partner_id, 'payout', v_period.total_amount,
    'Monthly payout ' || v_period.period_yyyymm || COALESCE(' — ' || p_note, '')
  ) RETURNING id INTO v_tx_id;

  UPDATE public.partner_payout_periods
     SET status = 'paid',
         paid_at = NOW(),
         paid_by = p_admin_id,
         payout_transaction_id = v_tx_id,
         note = p_note
   WHERE id = p_period_id;

  RETURN v_tx_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

GRANT EXECUTE ON FUNCTION public.mark_partner_payout_paid(UUID, UUID, TEXT) TO authenticated;


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000020_partner_security_hardening.sql
-- ════════════════════════════════════════════════════════════════════════

-- Phase 1 P2 — final security hardening pass.
--
-- 1. Sprint 20 shipped a public RLS policy on bookings keyed only on
--    `partner_invoice_token IS NOT NULL`, which exposed every partner-managed
--    booking to anonymous readers (Postgres RLS evaluates the policy without
--    seeing the client-supplied filter, so the predicate is effectively a
--    table-wide allow). Replace it with a SECURITY DEFINER lookup function
--    that returns a single row only when the supplied token matches.
--
-- 2. mark_partner_payout_paid() was trusting the caller-supplied p_admin_id
--    without verifying the caller actually has the mogzu_admin role.
--    Re-derive the admin id from auth.uid() and reject non-admins.

-- ─── 1. Lock down the partner invoice public read ────────────────────────────

DROP POLICY IF EXISTS "Anyone can read booking via invoice token" ON public.bookings;

CREATE OR REPLACE FUNCTION public.get_booking_by_invoice_token(p_token TEXT)
RETURNS TABLE (
  id UUID,
  corporate_id UUID,
  listing_id UUID,
  module TEXT,
  status TEXT,
  group_size INTEGER,
  total_amount NUMERIC,
  base_amount NUMERIC,
  add_ons_amount NUMERIC,
  platform_fee NUMERIC,
  partner_id UUID,
  partner_markup_pct NUMERIC,
  partner_margin_amount NUMERIC,
  partner_invoice_token TEXT,
  created_at TIMESTAMPTZ,
  listing_title TEXT,
  listing_city TEXT,
  corporate_name TEXT
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    b.id, b.corporate_id, b.listing_id, b.module, b.status, b.group_size,
    b.total_amount, b.base_amount, b.add_ons_amount, b.platform_fee,
    b.partner_id, b.partner_markup_pct, b.partner_margin_amount,
    b.partner_invoice_token, b.created_at,
    l.title AS listing_title,
    l.location_city AS listing_city,
    c.name AS corporate_name
  FROM public.bookings b
  LEFT JOIN public.listings l ON l.id = b.listing_id
  LEFT JOIN public.corporate_accounts c ON c.id = b.corporate_id
  WHERE b.partner_invoice_token IS NOT NULL
    AND b.partner_invoice_token = p_token
  LIMIT 1;
$$;

GRANT EXECUTE ON FUNCTION public.get_booking_by_invoice_token(TEXT) TO anon, authenticated;

-- ─── 2. Require mogzu_admin for payout marking ───────────────────────────────

CREATE OR REPLACE FUNCTION public.mark_partner_payout_paid(
  p_period_id UUID,
  p_admin_id UUID,
  p_note TEXT DEFAULT NULL
) RETURNS UUID AS $$
DECLARE
  v_period RECORD;
  v_wallet_id UUID;
  v_tx_id UUID;
  v_caller UUID := auth.uid();
BEGIN
  -- Only callable by the platform admin. p_admin_id is kept in the signature
  -- for backward compatibility but it is no longer trusted — the recorded
  -- paid_by always comes from the authenticated session.
  IF v_caller IS NULL OR NOT EXISTS (
    SELECT 1 FROM public.user_profiles
     WHERE id = v_caller AND role = 'mogzu_admin'
  ) THEN
    RAISE EXCEPTION 'mark_partner_payout_paid: caller is not a mogzu admin';
  END IF;

  SELECT * INTO v_period FROM public.partner_payout_periods
   WHERE id = p_period_id AND status = 'pending';
  IF NOT FOUND THEN RETURN NULL; END IF;
  IF v_period.total_amount <= 0 THEN RETURN NULL; END IF;

  SELECT id INTO v_wallet_id FROM public.partner_wallets
   WHERE partner_id = v_period.partner_id;
  IF v_wallet_id IS NULL THEN
    INSERT INTO public.partner_wallets (partner_id)
    VALUES (v_period.partner_id) RETURNING id INTO v_wallet_id;
  END IF;

  INSERT INTO public.partner_wallet_transactions (
    partner_wallet_id, partner_id, type, amount, description
  ) VALUES (
    v_wallet_id, v_period.partner_id, 'payout', v_period.total_amount,
    'Monthly payout ' || v_period.period_yyyymm || COALESCE(' — ' || p_note, '')
  ) RETURNING id INTO v_tx_id;

  UPDATE public.partner_payout_periods
     SET status = 'paid',
         paid_at = NOW(),
         paid_by = v_caller,
         payout_transaction_id = v_tx_id,
         note = p_note
   WHERE id = p_period_id;

  RETURN v_tx_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000021_rbac_sub_users.sql
-- ════════════════════════════════════════════════════════════════════════

-- Phase 2 — Feature 6: Sub-Users & RBAC.
--
-- Adds two new internal roles (sales_agent, field_agent), a per-user
-- permission grant table, and a lightweight activity log for sub-user
-- actions. The existing 'support' role continues to cover the PRD's
-- "Customer Support" persona; 'account_manager' covers Account Manager;
-- 'partner' covers External Partner.

-- ─── 1. Expand UserRole CHECK ────────────────────────────────────────────────

ALTER TABLE public.user_profiles
  DROP CONSTRAINT IF EXISTS user_profiles_role_check;

ALTER TABLE public.user_profiles DROP CONSTRAINT IF EXISTS user_profiles_role_check;
ALTER TABLE public.user_profiles
  ADD CONSTRAINT user_profiles_role_check CHECK (
    role IN (
      'l1_employee', 'l2_manager', 'l3_admin',
      'vendor', 'mogzu_admin', 'account_manager',
      'partner', 'support',
      'sales_agent', 'field_agent'
    )
  );

ALTER TABLE public.user_profiles
  ADD COLUMN IF NOT EXISTS invited_by UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS invited_at TIMESTAMPTZ;

-- Extend the status enum to support the invited lifecycle. Existing rows
-- with 'active' / 'deactivated' are untouched.
ALTER TABLE public.user_profiles
  DROP CONSTRAINT IF EXISTS user_profiles_status_check;

ALTER TABLE public.user_profiles DROP CONSTRAINT IF EXISTS user_profiles_status_check;
ALTER TABLE public.user_profiles
  ADD CONSTRAINT user_profiles_status_check CHECK (
    status IN ('active', 'deactivated', 'invited')
  );

-- ─── 2. Per-user permission grants ───────────────────────────────────────────
--
-- Granular allow-list. The (role) provides a baseline; this table layers
-- additional grants on top. Admin tooling toggles rows; server-side checks
-- go through private.user_can() so we can reuse it from RLS.

CREATE TABLE IF NOT EXISTS public.user_permissions (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  user_id UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  resource TEXT NOT NULL,
  action TEXT NOT NULL CHECK (action IN ('view', 'create', 'update', 'delete', 'approve')),
  granted_by UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (user_id, resource, action)
);

CREATE INDEX IF NOT EXISTS idx_user_permissions_user ON public.user_permissions (user_id);

ALTER TABLE public.user_permissions ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Users read own permissions" ON public.user_permissions;
CREATE POLICY "Users read own permissions" ON public.user_permissions
  FOR SELECT
  USING (user_id = auth.uid());

DROP POLICY IF EXISTS "Admin manages all permissions" ON public.user_permissions;
CREATE POLICY "Admin manages all permissions" ON public.user_permissions
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  );

CREATE OR REPLACE FUNCTION private.user_can(p_resource TEXT, p_action TEXT)
RETURNS BOOLEAN AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.user_permissions
     WHERE user_id = auth.uid()
       AND resource = p_resource
       AND action = p_action
  )
$$ LANGUAGE SQL SECURITY DEFINER STABLE;

-- ─── 3. Activity log for sub-users ───────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.user_activity_events (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  actor_id UUID NOT NULL REFERENCES public.user_profiles(id) ON DELETE CASCADE,
  event_type TEXT NOT NULL,
  target_table TEXT,
  target_id UUID,
  metadata JSONB NOT NULL DEFAULT '{}'::JSONB,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_user_activity_actor
  ON public.user_activity_events (actor_id, created_at DESC);

ALTER TABLE public.user_activity_events ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "User reads own activity" ON public.user_activity_events;
CREATE POLICY "User reads own activity" ON public.user_activity_events
  FOR SELECT
  USING (actor_id = auth.uid());

DROP POLICY IF EXISTS "Admin reads all activity" ON public.user_activity_events;
CREATE POLICY "Admin reads all activity" ON public.user_activity_events
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  );

DROP POLICY IF EXISTS "Any authenticated user inserts own activity" ON public.user_activity_events;
CREATE POLICY "Any authenticated user inserts own activity" ON public.user_activity_events
  FOR INSERT
  WITH CHECK (actor_id = auth.uid());

-- ─── 4. Invite tokens ────────────────────────────────────────────────────────
--
-- Admin creates a pending sub-user row with an invite token. The user opens
-- /invite/:token to choose a password, which triggers a normal supabase
-- signup. On first sign-in the application binds the auth.users row to the
-- pre-seeded user_profiles row (matched by email) and clears the token.

CREATE TABLE IF NOT EXISTS public.user_invites (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  email TEXT NOT NULL,
  role TEXT NOT NULL,
  full_name TEXT,
  token TEXT NOT NULL UNIQUE,
  invited_by UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  expires_at TIMESTAMPTZ NOT NULL DEFAULT (NOW() + INTERVAL '14 days'),
  accepted_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_user_invites_token ON public.user_invites (token);
CREATE INDEX IF NOT EXISTS idx_user_invites_email ON public.user_invites (lower(email));

ALTER TABLE public.user_invites ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Admin manages all invites" ON public.user_invites;
CREATE POLICY "Admin manages all invites" ON public.user_invites
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'mogzu_admin'
    )
  );

-- Public lookup goes through a SECURITY DEFINER RPC so the table itself
-- stays admin-only — same hardening pattern as the partner invoice token.
CREATE OR REPLACE FUNCTION public.get_user_invite_by_token(p_token TEXT)
RETURNS TABLE (
  id UUID,
  email TEXT,
  role TEXT,
  full_name TEXT,
  expires_at TIMESTAMPTZ,
  accepted_at TIMESTAMPTZ
)
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT id, email, role, full_name, expires_at, accepted_at
    FROM public.user_invites
   WHERE token = p_token
   LIMIT 1;
$$;

GRANT EXECUTE ON FUNCTION public.get_user_invite_by_token(TEXT) TO anon, authenticated;

CREATE OR REPLACE FUNCTION public.accept_user_invite(p_token TEXT)
RETURNS UUID AS $$
DECLARE
  v_invite RECORD;
  v_user UUID := auth.uid();
BEGIN
  IF v_user IS NULL THEN
    RAISE EXCEPTION 'accept_user_invite: must be signed in';
  END IF;

  SELECT * INTO v_invite FROM public.user_invites
   WHERE token = p_token
     AND accepted_at IS NULL
     AND expires_at > NOW();
  IF NOT FOUND THEN RETURN NULL; END IF;

  -- Bind the freshly signed-up auth user to the role + invite metadata.
  UPDATE public.user_profiles
     SET role = v_invite.role,
         full_name = COALESCE(v_invite.full_name, full_name),
         status = 'active',
         invited_by = v_invite.invited_by,
         invited_at = v_invite.created_at
   WHERE id = v_user;

  UPDATE public.user_invites
     SET accepted_at = NOW()
   WHERE id = v_invite.id;

  RETURN v_invite.id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

GRANT EXECUTE ON FUNCTION public.accept_user_invite(TEXT) TO authenticated;


-- ════════════════════════════════════════════════════════════════════════
-- 20260516000022_status_tracker_proof.sql
-- ════════════════════════════════════════════════════════════════════════

-- Phase 2 — Features 2 & 3:
-- Live status tracker + proof of execution, and proof-of-conditions.
--
-- A single booking_status_events table covers all three modules; the
-- allowed stage list is module-aware but enforced in app code, not in
-- a CHECK constraint (CHECKs can't read other tables in vanilla
-- Postgres). The mandatory proof fields (otp_verified_at, photo_path,
-- gps_lat / lng) are set together at submit time, and once
-- otp_verified_at is non-null the row becomes immutable via trigger.

-- ─── booking_status_events ───────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.booking_status_events (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  booking_id UUID NOT NULL REFERENCES public.bookings(id) ON DELETE CASCADE,
  stage TEXT NOT NULL,
  otp_code TEXT,
  otp_sent_to TEXT,
  otp_verified_at TIMESTAMPTZ,
  photo_path TEXT,
  gps_lat NUMERIC(9, 6),
  gps_lng NUMERIC(9, 6),
  submitted_by UUID REFERENCES public.user_profiles(id) ON DELETE SET NULL,
  submitted_at TIMESTAMPTZ,
  notes TEXT,
  admin_override_reason TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_booking_status_events_booking
  ON public.booking_status_events (booking_id, created_at DESC);
CREATE UNIQUE INDEX IF NOT EXISTS uniq_booking_status_events_stage
  ON public.booking_status_events (booking_id, stage);

DROP TRIGGER IF EXISTS trg_booking_status_events_updated_at ON public.booking_status_events;
CREATE TRIGGER trg_booking_status_events_updated_at
  BEFORE UPDATE ON public.booking_status_events
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

CREATE OR REPLACE FUNCTION public.booking_status_events_lock_verified()
RETURNS TRIGGER AS $$
BEGIN
  -- Once OTP-verified, only admin override + reason fields may change.
  IF OLD.otp_verified_at IS NOT NULL THEN
    IF NEW.stage <> OLD.stage
       OR NEW.otp_code IS DISTINCT FROM OLD.otp_code
       OR NEW.otp_verified_at <> OLD.otp_verified_at
       OR NEW.photo_path IS DISTINCT FROM OLD.photo_path
       OR NEW.gps_lat IS DISTINCT FROM OLD.gps_lat
       OR NEW.gps_lng IS DISTINCT FROM OLD.gps_lng
       OR NEW.submitted_by IS DISTINCT FROM OLD.submitted_by
       OR NEW.submitted_at IS DISTINCT FROM OLD.submitted_at
    THEN
      RAISE EXCEPTION 'booking_status_events: row is immutable after OTP verification (only admin notes may change)';
    END IF;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_booking_status_events_lock ON public.booking_status_events;
CREATE TRIGGER trg_booking_status_events_lock
  BEFORE UPDATE ON public.booking_status_events
  FOR EACH ROW EXECUTE FUNCTION public.booking_status_events_lock_verified();

ALTER TABLE public.booking_status_events ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Corporate reads booking status events" ON public.booking_status_events;
CREATE POLICY "Corporate reads booking status events" ON public.booking_status_events
  FOR SELECT
  USING (
    booking_id IN (
      SELECT b.id FROM public.bookings b
      JOIN public.user_profiles p ON p.corporate_id = b.corporate_id
      WHERE p.id = auth.uid()
    )
  );

DROP POLICY IF EXISTS "Vendor reads + writes own booking status events" ON public.booking_status_events;
CREATE POLICY "Vendor reads + writes own booking status events" ON public.booking_status_events
  FOR ALL
  USING (
    booking_id IN (
      SELECT b.id FROM public.bookings b
      JOIN public.vendors v ON v.id = b.vendor_id
      WHERE v.user_id = auth.uid()
    )
  )
  WITH CHECK (
    booking_id IN (
      SELECT b.id FROM public.bookings b
      JOIN public.vendors v ON v.id = b.vendor_id
      WHERE v.user_id = auth.uid()
    )
  );

DROP POLICY IF EXISTS "Field agent reads + writes assigned bookings" ON public.booking_status_events;
CREATE POLICY "Field agent reads + writes assigned bookings" ON public.booking_status_events
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'field_agent'
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role = 'field_agent'
    )
  );

DROP POLICY IF EXISTS "Admin full access to status events" ON public.booking_status_events;
CREATE POLICY "Admin full access to status events" ON public.booking_status_events
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role IN ('mogzu_admin', 'support')
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role IN ('mogzu_admin', 'support')
    )
  );

-- ─── booking_proof_records (Feature 3) ───────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.booking_proof_records (
