  BEFORE UPDATE ON public.booking_proof_records
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

ALTER TABLE public.booking_proof_records ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Corporate reads own proof record" ON public.booking_proof_records;
CREATE POLICY "Corporate reads own proof record" ON public.booking_proof_records
  FOR SELECT
  USING (
