    )
  );

DROP POLICY IF EXISTS "Admin full access to proof records" ON public.booking_proof_records;
CREATE POLICY "Admin full access to proof records" ON public.booking_proof_records
  FOR ALL
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role IN ('mogzu_admin', 'support')
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid() AND p.role IN ('mogzu_admin', 'support')
