    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('mogzu_admin', 'support', 'sales_agent')
    )
  );

DROP POLICY IF EXISTS "Admin + sales read submissions" ON public.quick_share_submissions;
CREATE POLICY "Admin + sales read submissions" ON public.quick_share_submissions
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('mogzu_admin', 'support', 'sales_agent')
    )
