DROP POLICY IF EXISTS "Admin + sales update submissions" ON public.quick_share_submissions;
CREATE POLICY "Admin + sales update submissions" ON public.quick_share_submissions
  FOR UPDATE
  USING (
    EXISTS (
      SELECT 1 FROM public.user_profiles p
